solution_code:
#include <array>
#include <iostream>

int main()
{
    std::array<std::array<int, 3>, 2> grid{};

    for (std::size_t r = 0; r < grid.size(); ++r)
        for (std::size_t c = 0; c < grid[r].size(); ++c)
            std::cin >> grid[r][c];

    std::array<std::array<int, 2>, 3> transposed{};

    for (std::size_t r = 0; r < grid.size(); ++r)
        for (std::size_t c = 0; c < grid[r].size(); ++c)
            transposed[c][r] = grid[r][c];

    for (std::size_t r = 0; r < transposed.size(); ++r)
    {
        for (std::size_t c = 0; c < transposed[r].size(); ++c)
        {
            if (c > 0) std::cout << ' ';
            std::cout << transposed[r][c];
        }
        std::cout << '\n';
    }

    return 0;
}

